const RALPH_APPEND_ENV = 'OMX_RALPH_APPEND_INSTRUCTIONS_FILE';
export function extractRalphTaskDescription(args) {
    const words = [];
    let i = 0;
    while (i < args.length) {
        const token = args[i];
        if (token === '--') {
            for (let j = i + 1; j < args.length; j++)
                words.push(args[j]);
            break;
        }
        if (token.startsWith('--') && token.includes('=')) {
            i++;
            continue;
        }
        if (token.startsWith('-') && VALUE_TAKING_FLAGS.has(token)) {
            i += 2;
            continue;
        }
        if (token.startsWith('-')) {
            i++;
            continue;
